import{_ as a,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"破仑","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/破仑.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/破仑.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/破仑.md"};function l(b,r,i,p,_,c){return t(),n("div",null,[...r[0]||(r[0]=[e("h1",{id:"破仑",tabindex:"-1"},[s("破仑 "),e("a",{class:"header-anchor",href:"#破仑","aria-label":'Permalink to "破仑"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004A")])])],-1),o('<h1 id="破仑-1" tabindex="-1">破仑 <a class="header-anchor" href="#破仑-1" aria-label="Permalink to &quot;破仑&quot;">​</a></h1><p>破仑<br> D+500<br> 外形：一个大木车轮，看起来有些腐朽，但不像一个真正的破轮子一样一碰即碎<br> 介绍：夫项羽，乃拔山盖世之雄，岂有一破仑而不能拿乎？<br> 武器类型：重盾 3L 双手 格挡9 钝击 体积4<br> 纵或挡道，乌骓但扬蹄，项羽即可过焉，何需下马将其移开，而后再行？岂不多此一举乎。<br> 一回合一次，你可以自由动作对你触及范围内的一名驾驶载具的敌人展示手中的这沉重的破仑，引起对方的警惕，你使用力量属性-武技-专业：盾牌对抗对方的决心-专注-专业：意志，若成功，本回合对方感受到这个破轮的威胁不会轻描淡写的略过这个破仑，而会尝试排除这个障碍，也就是只会对你发动攻击，这是一个D级心灵来源的胁迫效果。<br> 一破仑，百数斤而已，令一、二士卒足以胜之，而何须劳项羽屈主帅之尊躬自动手乎？<br> 若持有者的力量属性达到11，则能以合适的姿势充分利用破仑的性能，装备破仑时持有者额外具有1点全伤害吸收。<br> 基于上述，余以为：项羽不必拿破仑。<br> ST选开：若存在项羽相关的血统/训练，ST可以静止破仑与该血统/训练同时使用。</p><p>民国初年，某学堂招考新生，作文命题为《项羽拿破仑论》。有某生者，于拿破仑素无所闻，见题后极为惶惑，继而忽有所“悟”，遂奋笔疾书，为文曰：<br> 夫项羽，乃拔山盖世之雄，岂有一破仑而不能拿乎？非不能也，实不必也。<br> 彼破仑，为何物？其大几许，其高若干？纵或挡道，乌骓但扬蹄，项羽即可过焉，何需下马将其移开，而后再行？岂不多此一举乎。<br> 退万步言，欲将其去之以利行军，然则彼一破仑，百数斤而已，令一、二士卒足以胜之，而何须劳项羽屈主帅之尊躬自动手乎？于情于理，无乃不合也！<br> 基于上述，余以为：项羽不必拿破仑。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=a(d,[["render",l]]);export{f as __pageData,m as default};
